import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
} from "@mui/material";


import { doctors } from "../data/doctors";

const DoctorProfile = () => {
  const { doctorId } = useParams();

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  if (!doctor) {
    return (
      <Container sx={{ py: 12, textAlign: "center" }}>
        <Typography variant="h4" color="error" gutterBottom>
          Doctor not found
        </Typography>
        <Button
          variant="contained"
          color="primary"
          sx={{ mt: 4 }}
          onClick={() => window.history.back()}
        >
          Go Back
        </Button>
      </Container>
    );
  }

  return (
    <Container
      maxWidth="xl"
      sx={{
        py: 10,
        px: { xs: 3, md: 8 },
        minHeight: "90vh",
      }}
    >
      <Paper
        elevation={6}
        sx={{
          p: { xs: 5, md: 10 },
          borderRadius: 4,
          maxWidth: 1400,
          mx: "auto",
          backgroundColor: "#ffffff",
          boxShadow: "0 16px 60px rgba(0,0,0,0.15)",
        }}
      >
        <Grid container spacing={8}>
                  { }
          <Grid item xs={12} md={5}>
            <Box sx={{ textAlign: "center" }}>
              <Avatar
                src={doctor.image}
                alt={doctor.name}
                sx={{
                  width: { xs: 280, md: 420 },
                  height: { xs: 280, md: 420 },
                  mx: "auto",
                  mb: 5,
                  border: "8px solid #e3f2fd",
                  boxShadow: 8,
                }}
              />
              <Typography variant="h3" sx={{ fontWeight: "bold", mb: 1 }}>
                {doctor.name}
              </Typography>
              <Typography variant="h5" color="primary">
                {doctor.specialty}
              </Typography>
            </Box>
          </Grid>

          {/* Details Section */}
          <Grid item xs={12} md={7}>
            <Typography
              variant="h4"
              gutterBottom
              sx={{ mb: 5, fontWeight: 600, color: "#1976d2" }}
            >
              Professional Details
            </Typography>

            <Divider sx={{ mb: 5, borderColor: "#1976d2" }} />

            <List disablePadding>
              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Experience</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.experience}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Qualification</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.qualification}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Availability</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.availability}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3, alignItems: "flex-start" }}>
                <ListItemText
                  primary={<Typography variant="h6">About</Typography>}
                  secondary={
                    <Typography
                      variant="body1"
                      sx={{ fontSize: "1.25rem", lineHeight: 1.8 }}
                    >
                      {doctor.bio}
                    </Typography>
                  }
                />
              </ListItem>
            </List>

            <Box sx={{ mt: 10, textAlign: "center" }}>
              <Button
                variant="contained"
                color="primary"
                size="large"
                sx={{
                  py: 3,
                  px: 10,
                  fontSize: "1.4rem",
                  borderRadius: 3,
                }}
              >
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
